/**
 * Individual Sign Up Page
 * 
 * Registration form for individual accounts. Collects personal information
 * including name, email, phone number with country code, and password.
 * Validates input and creates individual user accounts.
 */

import React, { useState } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { apiRequest } from '@/shared/services/apiClient.js';
import { useNavigate } from 'react-router-dom';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { LanguageSelector, FlagIcon, PasswordRequirements, LoadingSpinner } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';
import logoLight from '@/assets/images/logo-light.png';
import logoDark from '@/assets/images/logo-dark.png';
import '/styles/index.css';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { createIndividualSignUpSchema } from '@/shared/utils/validation/authSchemas.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';

const IndividualSignUp = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { success, error: showError } = useToast();
  const { effectiveTheme } = useTheme();

  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;
  const [formData, setFormData] = useState({
    firstName: '',
    surname: '',
    email: '',
    countryCode: '+233',
    phone: '',
    password: '',
    confirmPassword: '',
  });

  const [error, setError] = useState('');
  const [formErrors, setFormErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const selectedCountry = countries.find(c => c.dialCode === formData.countryCode) || countries.find(c => c.code === 'GH');

  const clearFieldError = (field) => {
    if (formErrors[field]) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[field];
        if (Object.keys(next).length === 1 && next._form) {
          delete next._form;
        }
        return next;
      });
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;

    if (name === 'phone' && value && value.startsWith('0')) {
      setFormData({ ...formData, [name]: value.substring(1) });
      if (error) { setError(''); }
      clearFieldError(name);
      return;
    }

    // Convert email to lowercase automatically
    const processedValue = name === 'email' ? value.toLowerCase() : value;

    setFormData({ ...formData, [name]: processedValue });
    if (error) { setError(''); }
    clearFieldError(name);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const schema = createIndividualSignUpSchema(t);
    const validation = schema.safeParse(formData);

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setFormErrors(errors);
      const message = Object.values(errors)[0] || t('pleaseFillAllFields', { ns: 'auth' });
      setError(message);
      showError(message);
      return;
    }

    const validated = validation.data;

    setError('');
    setFormErrors({});
    setLoading(true);

    try {
      const cleanedPhone = cleanNumberForBackend(validated.phone);
      const cleanedCountryCode = cleanNumberForBackend(validated.countryCode);
      const payload = {
        email: validated.email,
        password: validated.password,
        first_name: validated.firstName,
        last_name: validated.surname,
        phone_number: `${cleanedCountryCode}${cleanedPhone}`,
      };

      const data = await apiRequest('/publicauth/register', {
        method: 'POST',
        body: JSON.stringify(payload),
      });

      success(t('individualAccountCreatedSuccessfully', { ns: 'auth' }));

      // Clear form
      setFormErrors({});
      setFormData({
        firstName: '',
        surname: '',
        email: '',
        countryCode: '+233',
        phone: '',
        password: '',
        confirmPassword: '',
      });

      setTimeout(() => navigate('/login'), 800);

    } catch (err) {
      let errorMessage = err.message || t('couldNotCompleteRequest', { ns: 'auth' });
      const lowerErrMessage = err.message?.toLowerCase() || '';

      // Check for account already exists errors
      if (err.message.includes('409') || lowerErrMessage.includes('already exist') || lowerErrMessage.includes('already exists')) {
        errorMessage = t('accountAlreadyExists', { ns: 'auth' });
      } else if (lowerErrMessage.includes('email') && (lowerErrMessage.includes('already') || lowerErrMessage.includes('taken'))) {
        errorMessage = t('emailAlreadyExists', { ns: 'auth' });
      } else if (lowerErrMessage.includes('phone') && (lowerErrMessage.includes('already') || lowerErrMessage.includes('taken'))) {
        errorMessage = t('phoneAlreadyExists', { ns: 'auth' });
      } else if (err.name === 'TypeError' && err.message.includes('Failed to fetch')) {
        errorMessage = t('unableToConnect', { ns: 'auth' });
      } else if (err.name === 'AbortError') {
        errorMessage = t('requestTimedOut', { ns: 'auth' });
      } else if (typeof navigator !== 'undefined' && navigator.onLine === false) {
        errorMessage = t('appearsOffline', { ns: 'auth' });
      }

      setError(errorMessage);
      showError(errorMessage);
    } finally {
      setLoading(false);
    }
  };
  return (
    <div className="login-container">
      <form className="login-form" onSubmit={handleSubmit} style={{ position: 'relative' }}>
        {/* Language Selector */}
        <div style={{
          position: 'absolute',
          top: '20px',
          right: '20px',
          zIndex: 10,
        }}>
          <LanguageSelector />
        </div>
        <img
          src={logoSrc}
          alt="iSmartPay Logo"
          className="login-logo"
          style={{
            transition: 'opacity var(--transition-theme)',
            opacity: 1
          }}
        />

        <h2 style={{ marginBottom: '24px' }}>{t('individualSignUp', { ns: 'auth' })}</h2>
        {(error || formErrors._form) && (
          <p className="error" style={{ marginBottom: '16px' }}>
            {formErrors._form ? formErrors._form : error}
          </p>
        )}

        <div className="input-wrapper" style={{ marginBottom: '16px' }}>
          <span className="input-icon"><i className="fa-solid fa-user"></i></span>
          <input
            type="text"
            name="firstName"
            placeholder={t('firstName', { ns: 'auth' })}
            value={formData.firstName}
            onChange={handleChange}
            disabled={loading}
            required
            style={{ marginBottom: 0 }}
          />
        </div>
        {formErrors.firstName && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '12px' }}>
            {formErrors.firstName}
          </p>
        )}

        <div className="input-wrapper" style={{ marginBottom: '16px' }}>
          <span className="input-icon"><i className="fa-solid fa-user"></i></span>
          <input
            type="text"
            name="surname"
            placeholder={t('surname', { ns: 'auth' })}
            value={formData.surname}
            onChange={handleChange}
            disabled={loading}
            required
            style={{ marginBottom: 0 }}
          />
        </div>
        {formErrors.surname && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '12px' }}>
            {formErrors.surname}
          </p>
        )}

        <div className="input-wrapper" style={{ marginBottom: '16px' }}>
          <span className="input-icon"><i className="fa-solid fa-envelope"></i></span>
          <input
            type="email"
            name="email"
            placeholder={t('emailAddress', { ns: 'auth' })}
            value={formData.email}
            onChange={handleChange}
            disabled={loading}
            required
            style={{ marginBottom: 0 }}
          />
        </div>
        {formErrors.email && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '12px' }}>
            {formErrors.email}
          </p>
        )}

        <div style={{ display: 'flex', gap: '8px', marginBottom: '16px', alignItems: 'center' }}>
          <div style={{ position: 'relative', width: '85px', flexShrink: 0, minWidth: '70px' }}>
            <CustomSelect
              name="countryCode"
              value={formData.countryCode}
              onChange={handleChange}
              disabled={loading}
              options={countries.map((country) => ({
                value: country.dialCode,
                label: country.dialCode,
                name: country.name,
                countryCode: country.code,
              }))}
              searchable
              showCheckmark={false}
              hasIcon={true}
            />
          </div>
          <div className="input-wrapper" style={{ flex: 1, marginBottom: 0 }}>
            <input
              type="tel"
              name="phone"
              placeholder={t('phoneNumber', { ns: 'auth' })}
              value={formData.phone}
              onChange={handleChange}
              disabled={loading}
              required
              style={{ paddingLeft: '15px', marginBottom: 0 }}
            />
          </div>
        </div>
        {(formErrors.countryCode || formErrors.phone) && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '12px' }}>
            {formErrors.phone || formErrors.countryCode}
          </p>
        )}

        <div className="input-wrapper" style={{ marginBottom: '16px', position: 'relative' }}>
          <span className="input-icon"><i className="fa-solid fa-key"></i></span>
          <input
            type={showPassword ? 'text' : 'password'}
            name="password"
            placeholder={t('password', { ns: 'auth' })}
            value={formData.password}
            onChange={handleChange}
            disabled={loading}
            required
            style={{ marginBottom: 0, paddingRight: '45px' }}
          />
          <button
            type="button"
            onClick={() => setShowPassword(!showPassword)}
            style={{
              position: 'absolute',
              right: '16px',
              top: '50%',
              transform: 'translateY(-50%)',
              background: 'none',
              border: 'none',
              color: '#6b7280',
              cursor: 'pointer',
              padding: '0',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              width: '20px',
              height: '20px'
            }}
            aria-label={showPassword ? t('hidePassword', { ns: 'auth' }) : t('showPassword', { ns: 'auth' })}
          >
            <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
          </button>
        </div>
        <PasswordRequirements password={formData.password} />
        {formErrors.password && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '8px', marginBottom: '12px' }}>
            {formErrors.password}
          </p>
        )}

        <div className="input-wrapper" style={{ marginBottom: '20px', position: 'relative' }}>
          <span className="input-icon"><i className="fa-solid fa-key"></i></span>
          <input
            type={showConfirmPassword ? 'text' : 'password'}
            name="confirmPassword"
            placeholder={t('confirmPassword', { ns: 'auth' })}
            value={formData.confirmPassword}
            onChange={handleChange}
            disabled={loading}
            required
            style={{ marginBottom: 0, paddingRight: '45px' }}
          />
          <button
            type="button"
            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
            style={{
              position: 'absolute',
              right: '16px',
              top: '50%',
              transform: 'translateY(-50%)',
              background: 'none',
              border: 'none',
              color: '#6b7280',
              cursor: 'pointer',
              padding: '0',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              width: '20px',
              height: '20px'
            }}
            aria-label={showConfirmPassword ? t('hidePassword', { ns: 'auth' }) : t('showPassword', { ns: 'auth' })}
          >
            <i className={`fa-solid ${showConfirmPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
          </button>
        </div>
        {formErrors.confirmPassword && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '12px' }}>
            {formErrors.confirmPassword}
          </p>
        )}

        <button
          type="submit"
          disabled={loading}
          style={{
            width: '100%',
            marginBottom: '20px',
            opacity: 1,
            cursor: 'pointer'
          }}
        >
          {t('signUp', { ns: 'auth' })}
        </button>

        {/* Loading spinner popup - outside the card */}
        {loading && createPortal(
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            width: '100vw',
            height: '100vh',
            backgroundColor: effectiveTheme === 'dark'
              ? 'rgba(0, 0, 0, 0.85)'
              : 'rgba(0, 0, 0, 0.5)',
            backdropFilter: 'blur(4px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 99999,
            margin: 0,
            padding: 0
          }}>
            <div style={{
              backgroundColor: effectiveTheme === 'dark'
                ? '#141414'
                : 'white',
              borderRadius: '16px',
              padding: '48px',
              boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              minWidth: '120px',
              minHeight: '120px'
            }}>
              <LoadingSpinner size="large" />
            </div>
          </div>,
          document.body
        )}

        <hr style={{ marginBottom: '16px' }} />
        <p style={{ textAlign: 'center', marginBottom: '16px' }}>{t('alreadyHaveAccount', { ns: 'auth' })}</p>

        <button
          type="button"
          onClick={() => navigate('/login')}
          style={{ width: '100%', backgroundColor: '#23bd00' }}
        >
          {t('signInButton', { ns: 'auth' })}
        </button>
      </form>
    </div>
  );
};

export default IndividualSignUp;
